SELECT a.id dataId, b.user_id id, b.user_name userName, b.company_id companyId, b.department_id departmentId, b.job_id jobId, b.email, b.job_number jobNumber FROM act_group_user a, sys_eve_user_staff b
a.user_id = b.user_id
AND a.group_id = #{objectId}
AND b.user_name LIKE '%${keyword}%'
AND a.tenant_id = #{tenantId}
group by b.id
